@csrf_exempt
def sso_acs(request):
    # Initialize the SAML authentication object
    auth = OneLogin_Saml2_Auth(request)

    # Process the POST response from the Identity Provider
    if 'SAMLResponse' in request.POST:
        auth.process_response()
